// Pega a resposta da IA (vem como texto)
const respostaIA = $input.first().json.output[0].content[0].text;

// Transforma o texto JSON em objeto JavaScript
const classificacao = JSON.parse(respostaIA);

// Pega os dados do e-mail original (Node 1 - Gmail)
const emailOriginal = $('Gmail Trigger').first().json;

// Gera um ID único para o ticket
const agora = new Date();
const timestamp = agora.getTime();
const idTicket = `TKT-${timestamp.toString().slice(-6)}`;

// Formata a data e hora no padrão brasileiro
const dataHora = agora.toLocaleString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

// Define o prazo de resposta baseado na urgência
let prazoResposta;
if (classificacao.urgencia === 'alta') {
  prazoResposta = 'até 2 horas';
} else if (classificacao.urgencia === 'media') {
  prazoResposta = 'até 4 horas';
} else {
  prazoResposta = 'até 1 dia útil';
}

// Retorna todos os dados organizados para o próximo node
return [{
  json: {
    id_ticket: idTicket,
    data_hora: dataHora,
    remetente: emailOriginal.From,
    assunto_original: emailOriginal['Subject'] || emailOriginal.subject || emailOriginal.snippet,
    categoria: classificacao.categoria,
    urgencia: classificacao.urgencia,
    resumo_ia: classificacao.resumo,
    nome_cliente: classificacao.nome_cliente,
    prazo_resposta: prazoResposta,
    email_resposta: emailOriginal.From,
    thread_id: emailOriginal.threadId
  }
}];

